// Match completed scores to pending games and calculate P/L
const FLAT_BET = 100;

const allInputs = $input.all();

// The merge node combines all items — scores are in the first input, pending in second
// We need to extract them from the merged data
const firstItem = allInputs[0].json;
const scoresData = firstItem.body || [];

// Build scores lookup by game ID
const scoresByID = {};
for (const event of scoresData) {
  if (!event.completed || !event.scores) continue;
  const scores = {};
  for (const s of event.scores) {
    if (s.score) scores[s.name] = parseInt(s.score);
  }
  if (Object.keys(scores).length >= 2) {
    const winner = Object.entries(scores).reduce((best, [name, score]) =>
      score > best[1] ? [name, score] : best, ['', -1])[0];
    scoresByID[event.id] = winner;
  }
}

// Get pending games (from second input onward after merge)
// With combineAll, each item has both inputs merged
// We need to access the pending games differently
const pendingItems = allInputs.slice(1);

const updated = [];
let wins = 0;
let losses = 0;
let totalProfit = 0;

for (const item of pendingItems) {
  const g = item.json;
  const gameId = g.game_id;

  if (!scoresByID[gameId]) continue;

  const winner = scoresByID[gameId];
  const dogWon = winner === g.underdog;
  const dogOdds = parseFloat(g.dog_odds_best);
  const profit = dogWon ? FLAT_BET * (dogOdds / 100) : -FLAT_BET;

  if (dogWon) wins++;
  else losses++;
  totalProfit += profit;

  updated.push({
    json: {
      game_id: gameId,
      row_number: g.row_number,
      winner: winner,
      dog_won: dogWon,
      profit: Math.round(profit * 100) / 100,
      // Pass through for message building
      underdog: g.underdog,
      favorite: g.favorite,
      dog_odds_best: g.dog_odds_best,
      bucket: g.bucket,
      date: g.date
    }
  });
}

if (updated.length === 0) {
  return [{ json: { _no_updates: true, _pending_count: pendingItems.length } }];
}

// Attach summary to first item
updated[0].json._summary = {
  updated: updated.length,
  wins: wins,
  losses: losses,
  total_profit: Math.round(totalProfit * 100) / 100
};

return updated;

// Build results Telegram message
const items = $input.all();
const summary = items[0].json._summary || {};
const today = new Date().toISOString().split('T')[0];

let msg = `⚾ *MLB Underdog Results — ${today}*\n\n`;
msg += `📊 *Updated: ${summary.updated} games*\n`;
msg += `Record today: ${summary.wins}W - ${summary.losses}L\n`;
msg += `P/L today: $${summary.total_profit >= 0 ? '+' : ''}${summary.total_profit}\n\n`;

for (const item of items) {
  const g = item.json;
  if (g._no_updates) continue;
  const icon = g.dog_won ? '✅' : '❌';
  const pl = g.profit >= 0 ? `+$${g.profit}` : `-$${Math.abs(g.profit)}`;
  msg += `${icon} *${g.underdog}* (+${g.dog_odds_best}) vs ${g.favorite}\n`;
  msg += `   ${g.dog_won ? 'WIN' : 'Loss'} | ${pl} | ${g.bucket}\n\n`;
}

return [{ json: { message: msg } }];

// No updates message
const pending = $input.first().json._pending_count || 0;
const today = new Date().toISOString().split('T')[0];

let msg = `⚾ *MLB Underdog Results — ${today}*\n\n`;
msg += `No completed games to update.\n`;
msg += `Pending games: ${pending}`;

return [{ json: { message: msg } }];
